import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);

  // 1. 사진 촬영 함수
  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  // 2. 사진 지우기 함수 (상태 초기화)
  const deletePhoto = () => {
    if (window.confirm("촬영한 사진을 삭제하시겠습니까?")) {
      setPhoto(null);
    }
  };

  return (
    <div style={containerStyle}>
      <div style={appCardStyle}>
        <div style={headerStyle}>
          <span style={logoIconStyle}>📸</span>
          <h1 style={titleStyle}>My Camera App</h1>
          <p style={subtitleStyle}>사진 촬영 및 관리 테스트</p>
        </div>

        <div style={previewContainerStyle}>
          {photo ? (
            <img src={photo} alt="촬영된 사진" style={photoStyle} />
          ) : (
            <div style={noPhotoStyle}>
              <span style={{ fontSize: "50px" }}>📷</span>
              <p style={{ marginTop: "10px", color: "#888" }}>
                촬영된 사진이 없습니다.
              </p>
            </div>
          )}
        </div>

        <div style={actionStyle}>
          {/* 사진이 없을 때: 촬영 버튼만 표시 */}
          {!photo && (
            <button onClick={takePhoto} style={buttonStyle}>
              사진 찍기
            </button>
          )}

          {/* 사진이 있을 때: 다시 찍기 & 삭제 버튼 표시 */}
          {photo && (
            <div style={{ display: "flex", gap: "10px", width: "100%" }}>
              <button onClick={takePhoto} style={{ ...buttonStyle, flex: 1 }}>
                다시 찍기
              </button>
              <button onClick={deletePhoto} style={deleteButtonStyle}>
                삭제하기
              </button>
            </div>
          )}
        </div>
      </div>

      <footer style={footerStyle}>
        <p>Created by Hyeon. Using React & Capacitor.</p>
      </footer>
    </div>
  );
}

// --- 스타일 정의 (기존 스타일 유지 및 삭제 버튼 추가) ---

const containerStyle = {
  backgroundColor: "#f0f2f5",
  minHeight: "100vh",
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  fontFamily:
    "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
};
const appCardStyle = {
  backgroundColor: "#fff",
  width: "100%",
  maxWidth: "400px",
  borderRadius: "20px",
  boxShadow: "0 10px 25px rgba(0,0,0,0.05)",
  padding: "30px",
  marginTop: "30px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const headerStyle = { textAlign: "center", marginBottom: "30px" };
const logoIconStyle = { fontSize: "40px" };
const titleStyle = {
  fontSize: "24px",
  fontWeight: "bold",
  margin: "10px 0 5px 0",
  color: "#333",
};
const subtitleStyle = { fontSize: "14px", color: "#777", margin: 0 };
const previewContainerStyle = {
  width: "100%",
  height: "300px",
  backgroundColor: "#f9f9f9",
  borderRadius: "15px",
  border: "2px dashed #ddd",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  overflow: "hidden",
  marginBottom: "30px",
};
const photoStyle = { width: "100%", height: "100%", objectFit: "cover" };
const noPhotoStyle = { textAlign: "center", color: "#bbb" };
const actionStyle = { width: "100%" };

const buttonStyle = {
  width: "100%",
  padding: "15px",
  fontSize: "16px",
  fontWeight: "bold",
  color: "#fff",
  backgroundColor: "#007aff",
  border: "none",
  borderRadius: "10px",
  cursor: "pointer",
  boxShadow: "0 4px 10px rgba(0,122,255,0.3)",
};

// 삭제 버튼 스타일 (경고를 의미하는 빨간색 계열)
const deleteButtonStyle = {
  flex: 1,
  padding: "15px",
  fontSize: "16px",
  fontWeight: "bold",
  color: "#ff3b30",
  backgroundColor: "#fff",
  border: "2px solid #ff3b30",
  borderRadius: "10px",
  cursor: "pointer",
};

const footerStyle = {
  marginTop: "auto",
  textAlign: "center",
  fontSize: "12px",
  color: "#aaa",
  paddingTop: "40px",
};

export default App;
